14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.numeric_std.all;
18	
19	library surf;
20	use surf.StdRtlPkg.all;
21	--use surf.TextUtilPkg.all;
22	
23	package ArbiterPkg is
24	
25	   function priorityEncode (v : slv; p : integer) return slv;
26	
27	   procedure arbitrate (
28	      req          : in    slv;
29	      lastSelected : in    slv;
30	      nextSelected : inout slv;
31	      valid        : inout sl;
32	      ack          : out   slv);
33	
34	end package ArbiterPkg;
35	
36	package body ArbiterPkg is
37	
38	   -- Priority encoder with index p having top priority
39	   -- followed by p-1, p-2, etc., rolling over to the highest index when 0 reached
40	   -- Returns highest priority index with value '1', encoded as unsigned slv.
41	   function priorityEncode (v : slv; p : integer) return slv is
42	      variable bestReq  : integer;
43	      variable rotatedV : unsigned(v'range);
44	      variable ret      : unsigned(bitSize(v'length-1)-1 downto 0) := (others => '0');
45	      variable bestReqU : unsigned(ret'length downto 0);
46	   begin
47	--      print("priorityEncode(" & str(v) & ", " & str(p) & ")");
48	      -- Rotate input by n to give n top priority
49	      rotatedV := rotate_right(unsigned(v), p);
50	
51	      -- Find lowest index with value of '1'
52	      bestReq := 0;
53	      for i in v'range loop
54	         if (rotatedV(i) = '1') then
55	            bestReq := i;
56	         end if;
57	      end loop;
58	
59	      -- Convert integer to unsigned
60	      bestReqU := to_unsigned(bestReq, bestReqU'length);
61	
62	      -- Add p to rotated select and mod by length to undo the rotation
63	      ret := resize((bestReqU+p) mod v'length, ret'length);
64	
65	      return slv(ret);
66	   end function priorityEncode;
67	
68	
69	   procedure arbitrate (
70	      req          : in    slv;
71	      lastSelected : in    slv;
72	      nextSelected : inout slv;
73	      valid        : inout sl;
74	      ack          : out   slv) is
75	   begin
76	--      print("arbitrate(" & str(req'length));-- & ", " & str(lastSelected'length) & ", " str(nextSelected'length) & ", " & ")");
77	      valid := uOr(req);
78	      if (valid = '1') then
79	         nextSelected := priorityEncode(req, to_integer(unsigned(lastSelected)+1) mod req'length);
80	         ack          := decode(slv(nextSelected))(req'range);
81	      else
82	         nextSelected   := lastSelected;
83	         ack(ack'range) := (others => '0');
84	      end if;
85	   end procedure arbitrate;
86	
87	end package body ArbiterPkg;
