24	entity Arbiter is
25	   generic (
26	      TPD_G          : time     := 1 ns;
27	      RST_POLARITY_G : sl       := '1';  -- '1' for active high rst, '0' for active low
28	      RST_ASYNC_G    : boolean  := false;  -- Reset is asynchronous
29	      REQ_SIZE_G     : positive := 16);
30	   port (
31	      clk : in sl;
32	      rst : in sl := not RST_POLARITY_G;   -- Optional reset
33	
34	      req      : in  slv(REQ_SIZE_G-1 downto 0);
35	      selected : out slv(bitSize(REQ_SIZE_G-1)-1 downto 0);
36	      valid    : out sl;
37	      ack      : out slv(REQ_SIZE_G-1 downto 0));
38	end entity Arbiter;
39	
40	architecture rtl of Arbiter is
41	
42	   constant SELECTED_SIZE_C : integer := bitSize(REQ_SIZE_G-1);
43	
44	   type RegType is record
45	      lastSelected : slv(SELECTED_SIZE_C-1 downto 0);
46	      valid        : sl;
47	      ack          : slv(REQ_SIZE_G-1 downto 0);
48	   end record RegType;
49	
50	   constant REG_INIT_C : RegType := (
51	      lastSelected => (others => '0'),
52	      valid        => '0',
53	      ack          => (others => '0'));
54	
55	   signal r   : RegType := REG_INIT_C;
56	   signal rin : RegType;
57	
58	begin
59	
60	   comb : process (r, req, rst) is
61	      variable v : RegType;
62	   begin
63	      v := r;
64	
65	      if (req(conv_integer(r.lastSelected)) = '0' or r.valid = '0') then
66	         arbitrate(req, r.lastSelected, v.lastSelected, v.valid, v.ack);
67	      end if;
68	
69	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
70	         v := REG_INIT_C;
71	      end if;
72	
73	      rin      <= v;
74	      ack      <= r.ack;
75	      valid    <= r.valid;
76	      selected <= slv(r.lastSelected);
77	
78	   end process comb;
