23	
24	entity Mux is
25	   generic (
26	      TPD_G          : time     := 1 ns;
27	      RST_POLARITY_G : sl       := '1';  -- '1' for active high rst, '0' for active low
28	      RST_ASYNC_G    : boolean  := false;
29	      REG_DIN_G      : boolean  := true;
30	      REG_SEL_G      : boolean  := true;
31	      REG_DOUT_G     : boolean  := true;
32	      SEL_WIDTH_G    : positive := 5);
33	   port (
34	      clk  : in  sl;
35	      rst  : in  sl := not(RST_POLARITY_G);
36	      sel  : in  slv(SEL_WIDTH_G-1 downto 0);
37	      din  : in  slv(2**SEL_WIDTH_G-1 downto 0);
38	      dout : out sl);
39	end Mux;
40	
41	architecture rtl of Mux is
42	
43	   type RegType is record
44	      sel  : unsigned(SEL_WIDTH_G-1 downto 0);
45	      din  : slv(2**SEL_WIDTH_G-1 downto 0);
46	      dout : sl;
47	   end record RegType;
48	   constant REG_INIT_C : RegType := (
49	      sel  => (others => '0'),
50	      din  => (others => '0'),
51	      dout => '0');
52	
53	   signal r   : RegType := REG_INIT_C;
54	   signal rin : RegType;
55	
56	begin
57	
58	   comb : process (din, r, rst, sel) is
59	      variable v : RegType;
60	   begin
61	      -- Latch the current value
62	      v := r;
63	
64	      -- Register input
65	      v.din := din;
66	
67	      -- typecast from slv to unsigned
68	      v.sel := unsigned(sel);
69	
70	      -- MUX
71	      if (REG_DIN_G = true) and (REG_SEL_G = true) then
