23	entity SimpleDualPortRam is
24	   generic (
25	      TPD_G          : time                       := 1 ns;
26	      RST_POLARITY_G : sl                         := '1';  -- '1' for active high rst, '0' for active low
27	      RST_ASYNC_G    : boolean                    := false;
28	      MEMORY_TYPE_G  : string                     := "block";
29	      DOB_REG_G      : boolean                    := false;  -- Extra reg on doutb (folded into BRAM)
30	      BYTE_WR_EN_G   : boolean                    := false;
31	      DATA_WIDTH_G   : integer range 1 to (2**24) := 16;
32	      BYTE_WIDTH_G   : integer                    := 8;  -- If BRAM, should be multiple or 8 or 9
33	      ADDR_WIDTH_G   : integer range 1 to (2**24) := 4;
34	      INIT_G         : slv                        := "0");
35	   port (
36	      -- Port A
37	      clka    : in  sl                                                    := '0';
38	      ena     : in  sl                                                    := '1';
39	      wea     : in  sl                                                    := '0';
40	      weaByte : in  slv(wordCount(DATA_WIDTH_G, BYTE_WIDTH_G)-1 downto 0) := (others => '0');
41	      addra   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
42	      dina    : in  slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
43	      -- Port B
44	      clkb    : in  sl                                                    := '0';
45	      enb     : in  sl                                                    := '1';
46	      regceb  : in  sl                                                    := '1';
47	      rstb    : in  sl                                                    := not(RST_POLARITY_G);
48	      addrb   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
49	      doutb   : out slv(DATA_WIDTH_G-1 downto 0));
50	end SimpleDualPortRam;
51	
52	architecture rtl of SimpleDualPortRam is
53	
54	   -- Set byte width to word width if byte writes not enabled
55	   -- Otherwise block ram parity bits wont be utilized
56	   constant BYTE_WIDTH_C      : natural := ite(BYTE_WR_EN_G, BYTE_WIDTH_G, DATA_WIDTH_G);
57	   constant NUM_BYTES_C       : natural := wordCount(DATA_WIDTH_G, BYTE_WIDTH_C);
58	   constant FULL_DATA_WIDTH_C : natural := NUM_BYTES_C*BYTE_WIDTH_C;
59	
60	   constant INIT_C : slv(FULL_DATA_WIDTH_C-1 downto 0) := ite(INIT_G = "0", slvZero(FULL_DATA_WIDTH_C), INIT_G);

